import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { orderAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';
import './OrdersPage.css';

const STATUS_COLOR = {
  PENDING: '#F59E0B', CONFIRMED: '#3B82F6', SHIPPED: '#8B5CF6',
  DELIVERED: '#10B981', CANCELLED: '#EF4444'
};

export default function OrdersPage() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (!user) { navigate('/login'); return; }
    orderAPI.getMyOrders()
      .then(({ data }) => { setOrders(Array.isArray(data) ? data : []); setLoading(false); })
      .catch(() => { setOrders([]); setLoading(false); });
  }, [user]);

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div className="orders-page">
      <div className="page-header"><h1>My Orders</h1><p>{orders.length} orders placed</p></div>
      <div className="container" style={{ paddingTop: 40 }}>
        {orders.length === 0 ? (
          <div className="empty-state">
            <p>📦 You haven't placed any orders yet.</p>
          </div>
        ) : (
          orders.map(order => (
            <div key={order.id} className="order-card">
              <div className="order-header">
                <div>
                  <span className="order-id">Order #{order.id}</span>
                  <span className="order-date">
                    {new Date(order.createdAt).toLocaleDateString('en-IN', {
                      day:'numeric', month:'short', year:'numeric'
                    })}
                  </span>
                </div>
                <span className="status-chip"
                  style={{ background: STATUS_COLOR[order.status] + '20',
                           color: STATUS_COLOR[order.status] }}>
                  ● {order.status}
                </span>
              </div>
              <div className="order-items">
                {order.items?.map(i => (
                  <div key={i.id} className="order-item-row">
                    <img src={i.product?.imageUrl} alt={i.product?.name} />
                    <div>
                      <p>{i.product?.name}</p>
                      <small>Qty: {i.quantity} × ₹{i.price?.toLocaleString('en-IN')}</small>
                    </div>
                    <span>₹{(i.price * i.quantity).toLocaleString('en-IN')}</span>
                  </div>
                ))}
              </div>
              <div className="order-footer">
                <span>📍 {order.shippingAddress}</span>
                <span className="order-total">Total: ₹{order.totalAmount?.toLocaleString('en-IN')}</span>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
